```class Solution {
public:
    bool canConstruct(string s, int k) {
        vector<int> count(26, 0);
        for (char c : s) {
            count[c - 'a']++;
        }
        int odd = 0;
        for (int i : count) {
            if (i % 2 != 0) {
                odd++;
            }
        }
        return odd <= k;
    }
};
